"use client"
import { useState } from "react";
import { useSearchParams, useRouter } from "next/navigation";
import { hashPassword } from "@/lib/hash";

export default function ResetPasswordPage() {
    const searchParams = useSearchParams();
    const email = searchParams.get("email");
    const [password, setPassword] = useState("");
    const [confirm, setConfirm] = useState("");
    const router = useRouter();

    const handleReset = async (e: any) => {
        e.preventDefault();
        if (password !== confirm) return alert("Password tidak cocok!");
        if (password.length < 8) return alert("Minimal 8 karakter!");

        const res = await fetch("/api/reset-password-final", {
        method: "POST",
        body: JSON.stringify({ email, password }),
        });

        if (res.ok) {
        alert("Password berhasil diganti!");
        router.push("/login");
        }
    };

    return (
        <div className="min-h-screen flex items-center justify-center bg-slate-900">
        <form onSubmit={handleReset} className="bg-white p-8 rounded-2xl w-80">
            <h2 className="font-bold mb-4">Reset Password</h2>
            <input 
            type="password" placeholder="New Password" 
            className="w-full border p-2 mb-2 rounded"
            onChange={(e) => setPassword(e.target.value)}
            />
            <input 
            type="password" placeholder="Confirm Password" 
            className="w-full border p-2 mb-4 rounded"
            onChange={(e) => setConfirm(e.target.value)}
            />
            <button className="w-full bg-blue-600 text-white p-2 rounded font-bold">Update Password</button>
        </form>
        </div>
    );
}